import React from "react";
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from "react-router-dom";
import AuctionList from "./pages/AuctionList";
import CreateRFQ from "./pages/CreateRFQ";
import AuctionDetail from "./pages/AuctionDetail";

const Navbar = () => {
  const navigate = useNavigate();
  return (
    <nav className="bg-gradient-to-r from-slate-900 via-blue-800 to-slate-900 text-white px-6 py-5 flex items-center justify-between shadow-2xl border-b-4 border-blue-400">
      <Link to="/" className="flex items-center space-x-3 hover:opacity-90 transition">
        <div className="bg-blue-400 text-slate-900 rounded-lg p-2.5">
          <svg className="w-6 h-6 font-bold" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M12 2a1 1 0 01.894.553l1.926 3.852a1 1 0 00.894.553h4.18a1 1 0 01.592 1.822l-3.38 2.456a1 1 0 00-.364 1.118l1.926 3.852a1 1 0 01-1.486 1.114L10 10.855l-3.382 2.457a1 1 0 01-1.486-1.114l1.926-3.852a1 1 0 00-.364-1.118L2.714 8.58A1 1 0 013.306 6.758h4.18a1 1 0 00.894-.553l1.926-3.852A1 1 0 0112 2z" clipRule="evenodd" />
          </svg>
        </div>
        <div>
          <div className="font-bold text-lg leading-tight">British Auction</div>
          <div className="text-xs font-light text-blue-200">RFQ System</div>
        </div>
      </Link>
      <div className="flex items-center space-x-6">
        <Link to="/" className="hover:text-blue-300 font-medium transition text-sm px-3 py-2 rounded hover:bg-blue-700/30">
          All Auctions
        </Link>
        <button
          className="bg-gradient-to-r from-blue-500 to-cyan-500 text-white font-semibold px-6 py-2.5 rounded-lg hover:from-blue-600 hover:to-cyan-600 transition shadow-lg"
          onClick={() => navigate("/create-rfq")}
        >
          <span className="flex items-center space-x-2">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
            <span>Create RFQ</span>
          </span>
        </button>
      </div>
    </nav>
  );
};

const App = () => {
  return (
    <Router>
      <Navbar />
      <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-slate-50">
        <Routes>
          <Route path="/" element={<AuctionList />} />
          <Route path="/create-rfq" element={<CreateRFQ />} />
          <Route path="/rfq/:id" element={<AuctionDetail />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
